var e=JSON.parse(`[{"id":"L5_1","type":"dialog","speaker":"MERCENARY_VOICE_NULL_A","text":{"KOREA":"빌어먹을......! 이 자식 카운터였어!","JPN":"くそっ……！　こいつ、カウンターだった！","ENG":"Darn it! This guy's a Counter!","TWN":"真該死……！這傢伙竟然是制裁者！"},"stage":{"bg":"BACKSTREET","slots":{"L":{"char_id":"MERCENARY_VOICE_NULL_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MERCENARY_VOICE_NULL_B","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"MERCENARY_VOICE_NULL_B","text":{"KOREA":"어디서 고용한 녀석이냐! 어서 불어!","JPN":"どこに雇われたんだ！　早く言え！","ENG":"Who paid you? You'd better fess up!","TWN":"你是誰雇的傢伙！快點說啊！"},"stage":{"bg":"BACKSTREET","slots":{"L":{"char_id":"MERCENARY_VOICE_NULL_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MERCENARY_VOICE_NULL_B","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"MERCENARY_VOICE_NULL_B","text":{"KOREA":"크억......!","JPN":"ガハッ……！","ENG":"Ack!","TWN":"唔呃……！"},"stage":{"bg":"BACKSTREET","slots":{"L":{"char_id":"MERCENARY_VOICE_NULL_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MERCENARY_VOICE_NULL_B","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"카운터면 죄다 돈 받아먹고 심부름 하러 다니는 줄 아냐?","JPN":"カウンターならみんな、金さえもらえば使い走りになるとでも思ってんのか？","ENG":"You reckon all Counters are just a bunch of errand boys and girls?","TWN":"你以為制裁者是拿錢只當跑腿的而已嗎？"},"stage":{"bg":"BACKSTREET","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"어디서 온 놈들인지 불기나 해. 여기가 누구 구역인지 알긴 하냐?","JPN":"どこから来たのか言え。ここが誰の縄張りかわかってるのか？","ENG":"Why don't you tell me where you're from? Are you even aware whose territory this is?","TWN":"你到底是從哪裡來的，趕快說啊，你知道這裡是誰的地盤嗎？"},"stage":{"bg":"BACKSTREET","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"MERCENARY_VOICE_NULL_C","text":{"KOREA":"흥. 네놈 때문에 우리 카지노가 간판 내리게 생겼어. 접수하느라 꽤 공들인 곳인데 말이야.","JPN":"ふん。お前のせいで、うちのカジノが潰れそうなんだ。手に入れるのに苦労したのによ。","ENG":"Hmpf! Our casino's about to close down because of you. It took us a lot of effort to claim this place.","TWN":"哼，因為你這傢伙，我們的賭場都快要關店了，為了接手我費了不少功夫呢。"},"stage":{"bg":"BACKSTREET","slots":{"L":null,"C":{"char_id":"MERCENARY_VOICE_NULL_C","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"MERCENARY_VOICE_NULL_C","text":{"KOREA":"누가 시켰는지 순순히 불어. 그럼 적어도 고통 없이 끝내주지.","JPN":"誰の指示か早く言え。そうすれば、すぐ楽にしてやる。","ENG":"Tell us who got you to do this. Then we'll make it short and painless when we kill you.","TWN":"到底誰主使的，你最好老實招供，至少我會讓你不感到痛苦地死去。"},"stage":{"bg":"BACKSTREET","slots":{"L":null,"C":{"char_id":"MERCENARY_VOICE_NULL_C","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"와아...... 손님 등쳐 먹는 놈들이 협박도 하네?","JPN":"うわ……客を騙したうえに脅迫まですんのか。","ENG":"Blimey... You lying cheats have the nerve to threaten me?","TWN":"哇啊……欺騙客人的傢伙還感威脅別人啊？"},"stage":{"bg":"BACKSTREET","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"딜러란 녀석이 손기술을 그렇게 대놓고 치는데 입이 안 근질거리겠냐?","JPN":"ディーラーがあんなに堂々とイカサマしたんだ。仕方ないだろ？","ENG":"I had to tell him off! That dealer was obviously trying to cheat!","TWN":"發牌的傢伙竟敢明目張膽地出老千，怎麼可能閉上嘴巴不講呢？"},"stage":{"bg":"BACKSTREET","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"MERCENARY_VOICE_NULL_C","text":{"KOREA":"쳇......!","JPN":"チッ……！","ENG":"Hmpf!","TWN":"切……！"},"stage":{"bg":"BACKSTREET","slots":{"L":null,"C":{"char_id":"MERCENARY_VOICE_NULL_C","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"꼬우면 어디 한 번 덤벼 보시던가. 우리 집안 신조가 <color=#ffd34c>오는 놈 안 막는다</color> 야.","JPN":"気に入らないなら、かかってこい。\\nうちのモットーは<color=#ffd34c>来るもの拒まず</color>だ。","ENG":"You're welcome to try me if you dare. After all, my family motto is, \\"<color=#ffd34c>If they're asking for it, give it to them</color>.\\"","TWN":"不高興的話就上來啊，我家的信條是 <color=#ffd34c>來者不拒</color>呢。"},"stage":{"bg":"BACKSTREET","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"MERCENARY_VOICE_NULL_C","text":{"KOREA":"......흥. 그래. 기억 났다.","JPN":"……ふん。ああそうだ、思い出した。","ENG":"Hmpf. I see. Now I remember.","TWN":"……哼，很好，我想起來了。"},"stage":{"bg":"BACKSTREET","slots":{"L":null,"C":{"char_id":"MERCENARY_VOICE_NULL_C","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"MERCENARY_VOICE_NULL_C","text":{"KOREA":"이 지역 놈들이 그러더군. 촌스러운 보라색 정장 입은 녀석과 엮이면 피곤해질 거라고.","JPN":"この辺のやつらが言ってたな。\\nダサい紫のスーツを着たやつと絡むと厄介なことになるって。","ENG":"I heard the local guys say something like this. Getting involved with a guy in a tacky purple suit will be a headache.","TWN":"這地區的傢伙曾經告訴我，說是有一個穿著土裡土氣紫色西裝的傢伙，若是被他纏上會很麻煩的。"},"stage":{"bg":"BACKSTREET","slots":{"L":null,"C":{"char_id":"MERCENARY_VOICE_NULL_C","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"핫, 그딴 소릴 누가 해? 내 앞에 데리고 와 보지 그래?","JPN":"は？　誰がそんなこと言ったんだ？　俺の前に連れて来い。","ENG":"Ha! Who's been telling you such nonsense? What don't you bring them to me?","TWN":"哈，那是誰說的？把他帶來給我看看？"},"stage":{"bg":"BACKSTREET","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"MERCENARY_VOICE_NULL_C","text":{"KOREA":"그건 안 되겠는걸. 지금쯤 바다 밑바닥에서 물고기들이랑 노느라 바쁠 테니까.","JPN":"それは無理だな。今頃、海の底で魚のエサになってるだろうからな。","ENG":"I'm afraid that won't be possible. They're probably too busy playing with the fishes at the bottom of the sea right now.","TWN":"這恐怕不行。因為他現在應該已經在海中大魚的肚子裡了。"},"stage":{"bg":"BACKSTREET","slots":{"L":null,"C":{"char_id":"MERCENARY_VOICE_NULL_C","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"이런...... 막 나가는 녀석들이셨구만.","JPN":"はあ……かなりヤバいやつらだな。","ENG":"Oh my... So you blokes like to play rough, don't you?","TWN":"該死的……原來是一群瘋子。"},"stage":{"bg":"BACKSTREET","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_HATE"},"R":null}}}]`);export{e as default};